import json

def summarize_assignment(assignment_text):
    # Extract relevant sections
    overall_summary = ""
    criteria_feedback = []
    for section in assignment_text.split("\n\n"):
        if section.startswith("overall_summary"):
            overall_summary = section.split("\n")[1]
        elif section.startswith("criteria_feedback"):
            criteria_feedback = section.split("\n")[1:]

    # Convert to structured JSON
    summary = {
        "overall_summary": overall_summary,
        "criteria_feedback": criteria_feedback
    }

    # Convert to valid JSON
    return json.dumps(summary)

